#include<bits/stdc++.h>
using namespace std;
const int maxn=2e5+5;
int n,a[maxn],b[maxn],i,ans=INT_MIN;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(i=1; i<=n; i++) {
		cin>>a[i];
		if(i==1) {
			b[i]=a[i];
		} else {
			b[i]=max(a[i],b[i-1]+a[i]);
		}
		ans=max(ans,b[i]);
	}
	cout<<ans;
	return 0;
}
